from flask import Flask, request, jsonify
import torch
from torchvision import models, transforms
from PIL import Image
import io

app = Flask(__name__)

# Load a pre-trained model
model = models.resnet50(pretrained=True)
model.eval()

# Define a simple transform
transform = transforms.Compose([
    transforms.Resize(256),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
])

# Load class names
with open("imagenet_classes.txt") as f:
    classes = [line.strip() for line in f.readlines()]

def secure_inference(image_tensor):
    # Implement secure inference techniques here
    # Placeholder for adversarial example prevention
    return model(image_tensor)

@app.route('/classify', methods=['POST'])
def classify_image():
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400

    file = request.files['file']
    image = Image.open(io.BytesIO(file.read()))
    image_tensor = transform(image).unsqueeze(0)

    with torch.no_grad():
        outputs = secure_inference(image_tensor)
        _, predicted = torch.max(outputs, 1)
        confidence = torch.nn.functional.softmax(outputs, dim=1)[0] * 100

    predicted_class = classes[predicted.item()]
    confidence_score = confidence[predicted.item()].item()

    return jsonify({'class': predicted_class, 'confidence': confidence_score})

